import React, { useState } from 'react';
import { TopNav } from '../TopNav';
import { Clock, Play, Square, Coffee } from 'lucide-react';

const logs = [
  { date: 'Mon, Jun 9',  checkIn: '09:02', checkOut: '17:58', break: '45 min', total: '8h 11m', status: 'Regular' },
  { date: 'Tue, Jun 10', checkIn: '08:55', checkOut: '18:10', break: '30 min', total: '8h 45m', status: 'Overtime' },
  { date: 'Wed, Jun 11', checkIn: '09:10', checkOut: '17:40', break: '60 min', total: '7h 30m', status: 'Regular' },
  { date: 'Thu, Jun 12', checkIn: '09:00', checkOut: '18:00', break: '45 min', total: '8h 15m', status: 'Regular' },
  { date: 'Fri, Jun 13', checkIn: '08:50', checkOut: '17:30', break: '30 min', total: '8h 10m', status: 'Regular' },
];

const statusColors = {
  Regular:  'bg-emerald-400/10 text-emerald-400',
  Overtime: 'bg-amber-400/10 text-amber-400',
  Absent:   'bg-red-400/10 text-red-400',
};

export default function TimeTrackingPage() {
  const [clocked, setClocked] = useState(false);
  const [onBreak, setOnBreak] = useState(false);

  return (
    <div className="flex flex-col min-h-full bg-dash-bg">
      <TopNav title="Time Tracking" />
      <main className="flex-1 p-6 space-y-6">

        {/* Clock card */}
        <div className="bg-dash-card border border-dash-border rounded-xl p-6 flex flex-col items-center gap-4">
          <div className="flex items-center gap-2 text-dash-text-muted" style={{ fontSize: '13px' }}>
            <Clock size={16} />
            <span>{new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}</span>
          </div>
          <p className="text-dash-text tabular-nums" style={{ fontSize: '48px', fontWeight: 700 }}>
            {new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })}
          </p>
          <div className="flex items-center gap-3">
            <button
              onClick={() => setClocked((v) => !v)}
              className={`flex items-center gap-2 px-5 py-2 rounded-lg transition-colors ${
                clocked ? 'bg-red-400/10 text-red-400 hover:bg-red-400/20' : 'bg-dash-primary text-white hover:bg-dash-primary/90'
              }`}
              style={{ fontSize: '13px', fontWeight: 500 }}
            >
              {clocked ? <><Square size={14} /> Clock Out</> : <><Play size={14} /> Clock In</>}
            </button>
            {clocked && (
              <button
                onClick={() => setOnBreak((v) => !v)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg border transition-colors ${
                  onBreak
                    ? 'border-amber-400 text-amber-400 bg-amber-400/10'
                    : 'border-dash-border text-dash-text-secondary hover:bg-dash-sidebar-hover'
                }`}
                style={{ fontSize: '13px' }}
              >
                <Coffee size={14} />
                {onBreak ? 'End Break' : 'Start Break'}
              </button>
            )}
          </div>
          {clocked && (
            <div className="flex items-center gap-1.5">
              <span className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse" />
              <span className="text-emerald-400" style={{ fontSize: '12px' }}>
                {onBreak ? 'On break' : 'Currently working'}
              </span>
            </div>
          )}
        </div>

        {/* Logs table */}
        <div className="bg-dash-card border border-dash-border rounded-xl overflow-hidden">
          <div className="px-5 py-4 border-b border-dash-border">
            <h3 className="text-dash-text" style={{ fontSize: '14px', fontWeight: 600 }}>Recent Logs</h3>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-dash-border">
                  {['Date', 'Check In', 'Check Out', 'Break', 'Total', 'Status'].map((h) => (
                    <th key={h} className="px-5 py-3 text-left text-dash-text-muted" style={{ fontSize: '11px', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                      {h}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {logs.map((row) => (
                  <tr key={row.date} className="border-b border-dash-border last:border-0 hover:bg-dash-sidebar-hover transition-colors">
                    <td className="px-5 py-3 text-dash-text" style={{ fontSize: '13px' }}>{row.date}</td>
                    <td className="px-5 py-3 text-dash-text-secondary" style={{ fontSize: '13px' }}>{row.checkIn}</td>
                    <td className="px-5 py-3 text-dash-text-secondary" style={{ fontSize: '13px' }}>{row.checkOut}</td>
                    <td className="px-5 py-3 text-dash-text-secondary" style={{ fontSize: '13px' }}>{row.break}</td>
                    <td className="px-5 py-3 text-dash-text" style={{ fontSize: '13px', fontWeight: 500 }}>{row.total}</td>
                    <td className="px-5 py-3">
                      <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${statusColors[row.status] || ''}`}>
                        {row.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

      </main>
    </div>
  );
}
